(() => {
  const section = document.querySelector('#periodo-colonial');
  const cards = section.querySelectorAll('[data-certeza]');
  const cardCount = cards.length;
  const hechoCount = section.querySelectorAll('[data-certeza="hecho"]').length;
  const opinionCount = section.querySelectorAll('[data-certeza="opinion"]').length;
  const rumorCount = section.querySelectorAll('[data-certeza="rumor"]').length;
  const gridHasCerteza = !!section.querySelector('.events-grid--certeza');
  const allHaveReveal = Array.from(cards).every(c => c.classList.contains('reveal') && c.classList.contains('reveal-slide'));
  const citeCount = section.querySelectorAll('footer.card-source cite').length;
  const opinionBlockquote = !!section.querySelector('blockquote.card-opinion__quote');
  const opinionAuthor = !!section.querySelector('.card-opinion__author');
  const opinionContext = !!section.querySelector('.card-opinion__context');
  const rumorOrigin = !!section.querySelector('.card-rumor__origin');
  const rumorOriginText = !!section.querySelector('.card-rumor__origin-text');
  const allHaveStagger = Array.from(cards).every(c => c.style.getPropertyValue('--reveal-delay'));
  const noPlaceholders = section.querySelectorAll('.event-card--placeholder').length === 0;

  return {
    cardCount, hechoCount, opinionCount, rumorCount,
    gridHasCerteza, allHaveReveal, citeCount,
    opinionBlockquote, opinionAuthor, opinionContext,
    rumorOrigin, rumorOriginText, allHaveStagger, noPlaceholders
  };
})()

