  const section = document.querySelector('#periodo-colonial');
  // Verify data-certeza values match card classes
  const cards = section.querySelectorAll('[data-certeza]');
  const mismatches = [];
  cards.forEach(c => {
    const certeza = c.getAttribute('data-certeza');
    const hasClass = c.classList.contains('card-' + (certeza === 'opinion' ? 'opinion' : certeza));
    if (!hasClass) mismatches.push({ certeza, classes: c.className });
  });

  // Verify stagger delays are correct sequence
  const delays = Array.from(cards).map(c => c.style.getPropertyValue('--reveal-delay'));

  return { 
    totalCards: cards.length,
    mismatches,
    delays,
    introText: section.querySelector('.period-intro p').textContent.substring(0, 50)
  };
})()

